import 'package:provider/provider.dart';import '../../core/constants/app_links.dart';import '../../core/services/launch_service.dart';import '../../data/state/portfolio_provider.dart';import '../home/widgets/section_container.dart';import '../home/widgets/section_title.dart';class ContactSection extends StatelessWidget {  const ContactSection({super.key});  @override  Widget build(BuildContext context) {    return SectionContainer(      child: Consumer<PortfolioProvider>(        builder: (context, vm, _) {          return Column(            crossAxisAlignment: CrossAxisAlignment.start,            children: [              const SectionTitle(                title: 'Contact',                subtitle: 'Let’s build something clean, fast, and premium.',              ),              const SizedBox(height: 20),              Text(                'I’m available for Android, Flutter, and UI-focused work.',                style: const TextStyle(height: 1.6),              ),              const SizedBox(height: 12),              Wrap(                spacing: 12,                runSpacing: 12,                children: [                  FilledButton(                    onPressed: () => LaunchService.open(                      vm.profile.email.startsWith('mailto:')                          ? vm.profile.email                          : 'mailto:${vm.profile.email}',                    ),                    child: const Text('Send Email'),                  ),                  OutlinedButton(                    onPressed: () => LaunchService.open(vm.profile.github),                    child: const Text('GitHub'),                  ),                  OutlinedButton(                    onPressed: () => LaunchService.open(vm.profile.linkedin),                    child: const Text('LinkedIn'),                  ),                  OutlinedButton(                    onPressed: () => LaunchService.open(vm.profile.telegram),                    child: const Text('Telegram'),                  ),                  OutlinedButton(                    onPressed: () => LaunchService.open(vm.profile.instagram),                    child: const Text('Instagram'),                  ),                  OutlinedButton(                    onPressed: () => LaunchService.open(AppLinks.playStore),                    child: const Text('Play Store'),                  ),                ],              ),            ],          );        },      ),    );  }}